import java.util.Scanner;

public class SecureBufferImplementation {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        char[] buffer = new char[10];
        int length = Math.min(input.length(), buffer.length); // Limit input length to buffer size

        // Implement boundary check to prevent buffer overflow
        for (int i = 0; i < length; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer overflow avoided. Output: " + new String(buffer));
    }
}

